import React, { useState } from 'react';

function SimpleCameraForm({ onNext, onCancel }) {
  const [rtspUrl, setRtspUrl] = useState('');
  const [image, setImage] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [error, setError] = useState('');

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImage(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!rtspUrl) {
      setError('Vui lòng nhập RTSP URL');
      return;
    }

    if (!image) {
      setError('Vui lòng upload ảnh camera');
      return;
    }

    onNext({
      rtspUrl,
      image,
      imagePreview
    });
  };

  return (
    <div className="simple-form">
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>RTSP URL:</label>
          <input
            type="text"
            value={rtspUrl}
            onChange={(e) => setRtspUrl(e.target.value)}
            placeholder="rtsp://username:password@ip:port/stream"
            className="form-control"
          />
        </div>

        <div className="form-group">
          <label>Ảnh Camera:</label>
          <input
            type="file"
            accept="image/*"
            onChange={handleImageChange}
            className="form-control"
          />
        </div>

        {imagePreview && (
          <div className="image-preview">
            <img src={imagePreview} alt="Preview" />
          </div>
        )}

        {error && <div className="error-message">{error}</div>}

        <div className="form-actions">
          <button type="button" onClick={onCancel} className="btn-cancel">
            Hủy
          </button>
          <button type="submit" className="btn-next">
            Tiếp theo →
          </button>
        </div>
      </form>

      <style jsx>{`
        .simple-form {
          padding: 20px;
        }

        .form-group {
          margin-bottom: 20px;
        }

        .form-group label {
          display: block;
          margin-bottom: 8px;
          font-weight: 500;
          color: #333;
        }

        .form-control {
          width: 100%;
          padding: 10px;
          border: 1px solid #ddd;
          border-radius: 4px;
          font-size: 14px;
        }

        .image-preview {
          margin: 15px 0;
          border: 1px solid #ddd;
          border-radius: 4px;
          overflow: hidden;
        }

        .image-preview img {
          width: 100%;
          height: auto;
          display: block;
        }

        .error-message {
          color: #dc3545;
          font-size: 14px;
          margin: 10px 0;
          padding: 10px;
          background: #f8d7da;
          border-radius: 4px;
        }

        .form-actions {
          display: flex;
          gap: 10px;
          margin-top: 20px;
        }

        .btn-cancel,
        .btn-next {
          flex: 1;
          padding: 12px;
          border: none;
          border-radius: 4px;
          font-size: 14px;
          font-weight: 500;
          cursor: pointer;
        }

        .btn-cancel {
          background: #6c757d;
          color: white;
        }

        .btn-next {
          background: #007bff;
          color: white;
        }

        .btn-cancel:hover {
          background: #5a6268;
        }

        .btn-next:hover {
          background: #0056b3;
        }
      `}</style>
    </div>
  );
}

export default SimpleCameraForm;
